       String renderSubtaskLine(Subtask s) {
         final check = s.completed ? '[x]' : '[ ]';
         final title = s.slug != null ? '[[${s.slug!}]]' : s.title;
         final fields = StringBuffer();
         if (s.dueDate != null) {
