This is a pure data class (NOT a ContentObject). It represents one essential
oil parsed from a collection Note row.

class OilEntry:
  FIELDS:
    String slug           // derived: title.toLowerCase().replaceAll(' ','-')
    String name           // display name, e.g. "Lavanda"
    String? emoji         // optional, e.g. "💜"
    String? description   // full description text (the note row body)
    String? properties    // comma-separated property tags, e.g. "calmante,sono,ansiedade"
    String? color         // hex color for UI, e.g. "#9B59B6"
    // User-selected visible properties (subset of properties to show on cards)
    List<String> visibleProperties   // default: all from properties

  CONSTRUCTOR: const OilEntry({required slug, required name, ...})

  factory OilEntry.fromCollectionRow(String rowText):
    // Parses a single line/row from the collection note body.
    // Expected format (flexible, graceful fallback):
    //   "💜 Lavanda | calmante, sono, ansiedade | Ajuda na ansiedade e relaxamento"
    //   OR "Lavanda :: calmante, sono :: Descrição longa"
    //   OR plain "Lavanda" (minimal)
    //
    // Parse logic:
    //   parts = rowText.split('|')  OR split('::')
    //   namePart = parts[0].trim() — extract emoji if starts with emoji char
    //   propertiesPart = parts.length > 1 ? parts[1].trim() : ''
    //   descPart = parts.length > 2 ? parts[2].trim() : ''
    //   slug = namePart without emoji, lowercased, spaces→dashes
    //   return OilEntry(slug, name, emoji, description: descPart, properties: propertiesPart)

  String get displayName => emoji != null ? '$emoji $name' : name

  List<String> get propertyList =>
    properties?.split(',').map((p) => p.trim()).where((p) => p.isNotEmpty).toList() ?? []

