FILE: lib/services/oil_collection_service.dart
ACTION: CREATE

PURPOSE: reads the aromatherapy collection Note and returns List<OilEntry>.
         Also persists per-oil visible property preferences.

class OilCollectionService:

  static List<OilEntry> parseFromNote(Note note):
    // note.subtype must be NoteSubtype.collection
    // note.body is the raw markdown/text of the collection
    // Split by newlines, filter empty lines and lines starting with '#'
    // For each line, call OilEntry.fromCollectionRow(line)
    // Return list, skipping nulls
    lines = note.body.split('\n')
    return lines
      .map((l) => l.trim())
      .where((l) => l.isNotEmpty && !l.startsWith('#'))
      .map(OilEntry.fromCollectionRow)
      .toList();

  static Map<String,List<String>> loadVisibleProperties(SharedPreferences prefs):
    // Key: 'oil_visible_props'
    // Value: JSON map of slug → List<String>
    raw = prefs.getString('oil_visible_props')
    if raw == null return {}
    return Map<String,List<String>>.from(
      (jsonDecode(raw) as Map).map((k,v) =>
        MapEntry(k as String, List<String>.from(v as List))))

  static Future<void> saveVisibleProperties(
      SharedPreferences prefs, Map<String,List<String>> map):
    await prefs.setString('oil_visible_props', jsonEncode(map))

