// Returns the aromatherapy collection Note (or null if not created yet).
// Detection: Note where title contains 'aromaterapia' (case-insensitive)
// OR where tags contains 'aromatherapy' OR 'aromaterapia'.
final aromatherapyNoteProvider = Provider<Note?>((ref) {
  final all = ref.watch(allObjectsProvider).valueOrNull ?? [];
  return all.whereType<Note>().cast<Note?>().firstWhere(
    (n) => n != null && (
      n.title.toLowerCase().contains('aromaterapia') ||
      n.tags.any((t) => t.toLowerCase().contains('aromaterapia') ||
                        t.toLowerCase().contains('aromatherapy'))
    ),
    orElse: () => null,
  );
});

// Returns parsed OilEntry list from the aromatherapy note.
final oilEntriesProvider = Provider<List<OilEntry>>((ref) {
  final note = ref.watch(aromatherapyNoteProvider);
  if (note == null) return [];
  return OilCollectionService.parseFromNote(note);
});

// Returns map of slug → List<String> of visible properties.
final oilVisiblePropsProvider = Provider<Map<String,List<String>>>((ref) {
  final prefs = ref.watch(sharedPreferencesProvider);
  return OilCollectionService.loadVisibleProperties(prefs);
});

// Returns the aromatherapy Habit (or null).
// Detection: Habit where title contains 'aromaterapia' OR tag 'aromatherapy'.
final aromatherapyHabitProvider = Provider<Habit?>((ref) {
  final all = ref.watch(allObjectsProvider).valueOrNull ?? [];
  return all.whereType<Habit>().cast<Habit?>().firstWhere(
    (h) => h != null && (
      h.title.toLowerCase().contains('aromaterapia') ||
      h.tags.any((t) => t.toLowerCase().contains('aromaterapia'))
    ),
    orElse: () => null,
  );
});

