ACTION: CREATE

PURPOSE: bar chart showing usage count per oil over a date range.
         Used inside the habit detail view AND optionally in tracker detail.

WIDGET: OilUsageChart extends ConsumerStatefulWidget
  CONSTRUCTOR params:
    Habit habit
    int daysBack = 30   // default: last 30 days

  STATE:
    int _daysBack  // initialized from widget.daysBack, user can change with toggle

  build(context):
    final cs = Theme.of(context).colorScheme;
    final oils = ref.watch(oilEntriesProvider);
    final cutoff = DateTime.now().subtract(Duration(days: _daysBack));

    // Aggregate usage: for each CompletionRecord in habit.completionHistory
    // where date >= cutoff, count each oil slug
    final Map<String,int> usageCounts = {};
    for (final record in habit.completionHistory) {
      if (record.date.isBefore(cutoff)) continue;
      for (final slug in record.oilSlugs) {
        usageCounts[slug] = (usageCounts[slug] ?? 0) + 1;
      }
    }

    if (usageCounts.isEmpty):
      return _EmptyOilChart();  // Simple message widget

    // Sort by count desc, take top 8
    final sorted = usageCounts.entries.toList()
      ..sort((a,b) => b.value.compareTo(a.value));
    final top = sorted.take(8).toList();

    return Column(children: [
      // Time range toggle
      Row(mainAxisAlignment: MainAxisAlignment.end, children: [
        for (final days in [7,30,90])
          GestureDetector(
            onTap: () => setState(() => _daysBack = days),
            child: Container(
              padding: EdgeInsets.symmetric(horizontal:10,vertical:4),
              margin: EdgeInsets.only(left:6),
              decoration: BoxDecoration(
                color: _daysBack == days ? cs.primary : cs.surface,
                borderRadius: BorderRadius.circular(20),
                border: Border.all(color: cs.outline.withValues(alpha:0.3)),
              ),
              child: Text('${days}d',
                style: TextStyle(fontSize:12,
                  color: _daysBack == days ? cs.onPrimary : cs.onSurface)),
            ),
          ),
      ]),
      SizedBox(height:12),

      // Horizontal bar chart using fl_chart BarChart
      // (fl_chart is already in the project — used in universal_detail_view)
      SizedBox(
        height: top.length * 44.0,  // dynamic height
        child: BarChart(
          BarChartData(
            barGroups: top.asMap().entries.map((e) {
              final oil = oils.firstWhere((o) => o.slug == e.value.key,
                orElse: () => OilEntry(slug: e.value.key, name: e.value.key));
              return BarChartGroupData(x: e.key, barRods: [
                BarChartRodData(
                  toY: e.value.value.toDouble(),
                  color: cs.primary,
                  width: 28,
                  borderRadius: BorderRadius.circular(6),
                ),
              ]);
            }).toList(),
            titlesData: FlTitlesData(
              leftTitles: AxisTitles(sideTitles: SideTitles(showTitles: false)),
              topTitles: AxisTitles(sideTitles: SideTitles(showTitles: false)),
              rightTitles: AxisTitles(sideTitles: SideTitles(showTitles: false)),
              bottomTitles: AxisTitles(sideTitles: SideTitles(
                showTitles: true,
                getTitlesWidget: (val, meta) {
                  final i = val.toInt();
                  if (i < 0 || i >= top.length) return const SizedBox();
                  final oil = oils.firstWhere((o) => o.slug == top[i].key,
                    orElse: () => OilEntry(slug: top[i].key, name: top[i].key));
                  return Padding(
                    padding: EdgeInsets.only(top:4),
                    child: Text(oil.emoji ?? oil.name.substring(0,1),
                      style: TextStyle(fontSize:11)),
                  );
                },
              )),
            ),
            borderData: FlBorderData(show: false),
            gridData: FlGridData(show: false),
          ),
        ),
      ),

      // Legend below chart
      SizedBox(height:12),
      Wrap(spacing:8, runSpacing:6,
        children: top.map((e) {
          final oil = oils.firstWhere((o) => o.slug == e.key,
            orElse: () => OilEntry(slug: e.key, name: e.key));
          return Container(
            padding: EdgeInsets.symmetric(horizontal:8, vertical:4),
            decoration: BoxDecoration(
              color: cs.surface,
              borderRadius: BorderRadius.circular(20),
              border: Border.all(color: cs.outline.withValues(alpha:0.3)),
            ),
            child: Text('${oil.displayName} · ${e.value}×',
              style: TextStyle(fontSize:11)),
          );
        }).toList(),
      ),
    ]);

